#include <stdio.h>

int main(void) {
    int arr[] = {10, 20, 30, 40, 50, 60};
    int *begin = arr;
    int *end = arr + 6;
    long count = end - begin;
    printf("Nombre d'elements : %ld\n", count);
    printf("sizeof(int) : %lu\n", (unsigned long)sizeof(int));
    printf("Taille totale : %lu octets\n", (unsigned long)sizeof(arr));
    printf("Elements via sizeof : %lu\n", (unsigned long)(sizeof(arr) / sizeof(arr[0])));
    return 0;
}

