#include <stdio.h>

/* == EXEMPLE ================================================
 * Difference de pointeurs sur un tableau de char
 * sizeof(char) == 1, donc difference == nombre d'octets.
 * =========================================================== */
void example_char_diff(void) {
    char msg[] = "Hello";
    char *begin = msg;
    char *end = msg + 5;
    long diff = end - begin;
    printf("Difference : %ld caracteres\n", diff);
    printf("sizeof(msg) : %lu (inclut '\\0')\n", (unsigned long)sizeof(msg));
    printf("Elements : %lu\n", (unsigned long)(sizeof(msg) / sizeof(msg[0])));
}
/* Resultat: Difference : 5 / sizeof(msg) : 6 / Elements : 6 */

